local LDefenceWarBaseActor = LXImport(".LDefenceWarBaseActor")

local LDefenceWarAniActor = LxClass("LDefenceWarAniActor", LDefenceWarBaseActor)
----------------------------------------------------------------
-----------------------------------------------------------------

function LDefenceWarAniActor:LDefenceWarAniActor()
    self._callMap = {}
end

-- 销毁
function LDefenceWarAniActor:OnDestroy()

end

-- Update
function LDefenceWarAniActor:Update(dt)

end

-- 播放动画
function LDefenceWarAniActor:PlayAni(aniName, loop, aniTime, timescale, mixTime)
    if aniName == self._aniName then
        return
    end
    self._aniName = aniName
    self._endTime = aniTime

    timescale = timescale or 1
    local dpObj = self:GetObj():GetDpObject()
    dpObj:SetAnimationTimeScale(timescale)
    dpObj:PlayAnimation(0, aniName, loop, false, mixTime)
end

-- 待机
function LDefenceWarAniActor:PlayIdle()
    self._endTime = nil
    self:PlayAni(LSpineAniConst.idle, true)
end

-- 移动
function LDefenceWarAniActor:PlayRun()
    self._endTime = nil
    self:PlayAni(LSpineAniConst.run, true)
end

-- 死亡
function LDefenceWarAniActor:PlayDie()
    -- local time = self:GetAnimationDuration(LSpineAniConst.die)
    -- self._obj:DestroySelf(time)
    self:PlayAni(LSpineAniConst.die, true)
    self:SetAniCallback()
end

-- 攻击
function LDefenceWarAniActor:PlayAtk(aniName, timescale, callback)
    self._endTime = nil

    aniName = aniName or "attack1"
    timescale = timescale or 1


    self._callMap[aniName] = callback
    self:PlayAni(aniName, false, nil, timescale)
    self:SetAniCallback()
end

-- 设置动画回调
function LDefenceWarAniActor:SetAniCallback()
    if self._hasSetCallback then
        return
    end
    self._hasSetCallback = true
    
    local dpObj = self:GetObj():GetDpObject()
    dpObj:SetAnimationCompleteFunc(function(...) self:OnPlayFinish(...) end)
end

-- 播放完成回调
function LDefenceWarAniActor:OnPlayFinish(aniName)
    if self._callMap[aniName] then
        self._callMap[aniName]()
        self._callMap[aniName] = nil
    end
    
    if aniName == LSpineAniConst.die then
        self._obj:DestroySelf()
    end
end

-- 获取动画长度
function LDefenceWarAniActor:GetAnimationDuration(aniName)
    return self._obj:GetDpObject():GetAnimationDuration(aniName)
end

-- 暂停
function LDefenceWarAniActor:OnPauseGame()
    local dpObj = self._obj:GetDpObject()
    dpObj:SetAnimationTimeScale(0)
end

-- 恢复
function LDefenceWarAniActor:OnResumeGame()
    local dpObj = self._obj:GetDpObject()
    dpObj:SetAnimationTimeScale(1)
end

return LDefenceWarAniActor
